# ============================================================================= # Remove Microsoft Edge and install Google Chrome # Runs as FirstLogon script with admin privileges # =============================================================================
$ErrorActionPreference = 'Continue' $logfile = 'C:\Windows\Setup\Scripts\EdgeChrome.log'
function Log { param($msg) "$(Get-Date -Format 'HH:mm:ss') $msg" | Tee-Object -FilePath $logfile -Append }
# ----------------------------------------------------------------------------- # 1. Remove Edge AppX packages (user + provisioned) # ----------------------------------------------------------------------------- Log "Removing Edge AppX packages..." Get-AppxPackage -AllUsers -Name '*MicrosoftEdge*' -ErrorAction SilentlyContinue | Remove-AppxPackage -AllUsers -ErrorAction Continue
Get-AppxProvisionedPackage -Online | Where-Object { $_.DisplayName -like '*MicrosoftEdge*' } | Remove-AppxProvisionedPackage -Online -AllUsers -ErrorAction Continue
# ----------------------------------------------------------------------------- # 2. Run Edge's own uninstaller (works for the stable channel binary) # ----------------------------------------------------------------------------- Log "Invoking Edge uninstaller..." $edgeBase = 'C:\Program Files (x86)\Microsoft\Edge\Application' if (Test-Path $edgeBase) { $setupExe = Get-ChildItem -Path $edgeBase -Recurse -Filter 'setup.exe' -ErrorAction SilentlyContinue | Where-Object { $_.FullName -match '\\Installer\\setup\.exe$' } | Select-Object -First 1
if ($setupExe) { # Allow uninstall despite the "system component" flag $uninstallKeys = @( 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\Microsoft Edge', 'HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\Microsoft Edge' ) foreach ($key in $uninstallKeys) { if (Test-Path $key) { Set-ItemProperty -Path $key -Name 'NoRemove' -Value 0 -Type DWord -Force -ErrorAction SilentlyContinue Remove-ItemProperty -Path $key -Name 'SystemComponent' -Force -ErrorAction SilentlyContinue } } Start-Process -FilePath $setupExe.FullName ` -ArgumentList '--uninstall', '--system-level', '--verbose-logging', '--force-uninstall' ` -Wait -NoNewWindow Log "Edge uninstaller completed." } else { Log "Edge setup.exe not found; skipping uninstaller." } }
# ----------------------------------------------------------------------------- # 3. Block Edge from reappearing via Windows Update / EdgeUpdate # ----------------------------------------------------------------------------- Log "Blocking Edge reinstall via policy..." $policyKey = 'HKLM:\SOFTWARE\Microsoft\EdgeUpdate' New-Item -Path $policyKey -Force | Out-Null Set-ItemProperty -Path $policyKey -Name 'DoNotUpdateToEdgeWithChromium' -Value 1 -Type DWord -Force Set-ItemProperty -Path $policyKey -Name 'InstallDefault' -Value 0 -Type DWord -Force
# ----------------------------------------------------------------------------- # 4. Clean up leftover shortcuts # ----------------------------------------------------------------------------- Log "Cleaning up Edge shortcuts..." $shortcuts = @( "$env:PUBLIC\Desktop\Microsoft Edge.lnk", "$env:USERPROFILE\Desktop\Microsoft Edge.lnk", "$env:ProgramData\Microsoft\Windows\Start Menu\Programs\Microsoft Edge.lnk" ) foreach ($s in $shortcuts) { Remove-Item -LiteralPath $s -Force -ErrorAction SilentlyContinue }
# ----------------------------------------------------------------------------- # 5. Wait for winget, then install Chrome # ----------------------------------------------------------------------------- Log "Waiting for winget to become available..." $deadline = (Get-Date).AddMinutes(5) while (-not (Get-Command winget -ErrorAction SilentlyContinue)) { if ((Get-Date) -gt $deadline) { Log "winget did not appear within 5 minutes; aborting Chrome install." return } Start-Sleep -Seconds 5 }
Log "Installing Google Chrome via winget..." winget install --id Google.Chrome ` --silent ` --accept-source-agreements ` --accept-package-agreements ` --scope machine 2>&1 | Tee-Object -FilePath $logfile -Append
Log "Done."

